const produtos = [
  { nome: 'Camisa', preco: 50, estoque: 10 },
  { nome: 'Calça', preco: 120, estoque: 0 },
  { nome: 'Tênis', preco: 200, estoque: 3 }
];

1) map: só nomes
const nomes = produtos.map(p => p.nome);

2) filter: só em estoque
const disponiveis = produtos.filter(p => p.estoque > 0);

3) reduce: total do estoque
const totalEstoque = produtos.reduce((acc, p) => acc + p.estoque, 0);

Isso é literalmente o que um dashboard faz.

