/* Aula 14 — modelJs: map / filter / reduce */

const pedidos = [
  { id: 1, total: 120.5, status: 'pago' },
  { id: 2, total: 80, status: 'pendente' },
  { id: 3, total: 50, status: 'pago' },
  { id: 4, total: 200, status: 'cancelado' }
];

// 1) map: ids
const ids = pedidos.map(p => p.id);
console.log('ids:', ids);

// 2) filter: pagos
const pagos = pedidos.filter(p => p.status === 'pago');
console.log('pagos:', pagos);

// 3) reduce: soma total
const somaTotal = pedidos.reduce((acc, p) => acc + p.total, 0);
console.log('somaTotal:', somaTotal);

// 4) total dos pagos (filter + reduce)
const somaPagos = pagos.reduce((acc, p) => acc + p.total, 0);
console.log('somaPagos:', somaPagos);
